<script lang="ts">
	import { pxToRem } from "../utils/pxToRem";

	interface Props {
		margin?: number;
		noLine?: boolean;
		dotted?: boolean;
	}

	const { margin = 12, noLine = false, dotted = false }: Props = $props();

	function getMargins() {
		if (margin === undefined) {
			return "";
		}

		return `margin-top: ${pxToRem(margin)}rem; margin-bottom: ${pxToRem(margin)}rem;`;
	}
</script>

<div
	class="divider"
	style={getMargins()}
	class:line={!noLine && !dotted}
	class:dotted={!noLine && dotted}
></div>

<style>.divider{height:.0625rem;opacity:.13;width:100%}.divider.line{background-color:var(--text-1)}.divider.dotted{background-image:linear-gradient(to right,var(--text-1) 50%,transparent 50%);background-size:.25rem .0625rem;opacity:.2}</style>
